                    redactJsonArray(arr)
                    arr.toString(2)
                }
                else -> null
            }
        } catch (_: Exception) {
            null
        }
    }

    private fun redactJsonObject(obj: JSONObject) {
        val keys = obj.keys()
        val toRedact = mutableListOf<String>()
        while (keys.hasNext()) {
            val key = keys.next()
            val lower = key.lowercase(Locale.US)
            when {
                lower.contains("password") || lower.contains("token") || lower.contains("secret") || lower.contains("authorization") -> toRedact.add(key)
                else -> {
                    val value = obj.opt(key)
                    when (value) {
                        is JSONObject -> redactJsonObject(value)
                        is JSONArray -> redactJsonArray(value)
                    }
                }
            }
        }
        toRedact.forEach { obj.put(it, "***") }
    }

    private fun redactJsonArray(arr: JSONArray) {
        for (i in 0 until arr.length()) {
            when (val value = arr.opt(i)) {
                is JSONObject -> redactJsonObject(value)
                is JSONArray -> redactJsonArray(value)
            }
        }
