    private fun sanitizeGeneric(value: Any?): Any? {
        return when (value) {
            null -> null
            is String -> if (value.length > 128) value.take(128) + "…" else value
            is ByteArray -> "[bytes:${value.size}]"
            is RequestBody -> "[request-body:${value.contentType()}]"
            is ResponseBody -> "[response-body:${value.contentType()}]"
            else -> value
        }
    }

    private fun mapToPrettyString(map: Map<String, Any?>): String {
        return map.entries.joinToString(prefix = "{", postfix = "}") { (k, v) -> "$k=$v" }
    }

    private fun String.maskEmailOrName(): String {
        val trimmed = trim()
        return when {
            trimmed.contains("@") -> {
                val parts = trimmed.split("@", limit = 2)
                val local = parts[0]
                val domain = parts[1]
                val maskedLocal = if (local.length <= 2) "*".repeat(local.length) else local.first() + "*".repeat(local.length - 2) + local.last()
                "$maskedLocal@$domain"
            }
            trimmed.length <= 2 -> "*".repeat(trimmed.length)
            else -> trimmed.first() + "*".repeat(min(trimmed.length - 2, 10)) + trimmed.last()
        }
    }
