class ApiLoggingInterceptor : Interceptor {
    override fun intercept(chain: Interceptor.Chain): okhttp3.Response {
        val request = chain.request()
        val requestId = request.header("X-Request-Id") ?: System.currentTimeMillis().toString()
        val headers = request.headers.toMultimap().mapValues { it.value.joinToString(",") }
        val bodyString = request.body?.let { bodyToString(it) }
        val startNs = System.nanoTime()

        AppLogger.logApiRequest(
            method = request.method,
            url = request.url.toString(),
            headers = headers,
            body = bodyString,
            requestId = requestId
        )

        return try {
            val response = chain.proceed(request)
            val durationMs = (System.nanoTime() - startNs) / 1_000_000
            val responseBodyString = response.peekBody(Long.MAX_VALUE).string()
            val responseHeaders = response.headers.toMultimap().mapValues { it.value.joinToString(",") }

            AppLogger.logApiResponse(
                method = request.method,
                url = request.url.toString(),
                statusCode = response.code,
                headers = responseHeaders,
                body = responseBodyString,
                durationMs = durationMs,
                requestId = requestId
            )
            response
        } catch (t: Throwable) {
            val durationMs = (System.nanoTime() - startNs) / 1_000_000
            AppLogger.e("API call failed: %s %s after %dms", request.method, request.url, durationMs)
            AppLogger.logException("API", t)
            throw t
        }
    }

    private fun bodyToString(requestBody: RequestBody): String {
        return try {
            val buffer = Buffer()
            requestBody.writeTo(buffer)
            buffer.readUtf8()
        } catch (e: Exception) {
            "[unavailable:${e.javaClass.simpleName}]"
        }
    }
}

class ProductionLoggingTree : Timber.Tree() {
