}

class ExceptionCatchingThreadFactory(
    private val delegate: java.util.concurrent.ThreadFactory = java.util.concurrent.Executors.defaultThreadFactory()
) : java.util.concurrent.ThreadFactory {
    override fun newThread(r: Runnable): Thread {
        val thread = delegate.newThread(r)
        thread.uncaughtExceptionHandler = Thread.UncaughtExceptionHandler { _, e ->
            AppLogger.logUnhandledException(e)
        }
        return thread
    }
}

inline fun <T> logDbOperation(
    databaseName: String,
    query: String,
    parameters: List<Any?> = emptyList(),
    operation: () -> T
): T {
    val start = System.currentTimeMillis()
    return try {
        val result = operation()
        AppLogger.logDatabaseQuery(databaseName, query, parameters, System.currentTimeMillis() - start, success = true)
        result
    } catch (t: Throwable) {
        AppLogger.logDatabaseQuery(databaseName, query, parameters, System.currentTimeMillis() - start, success = false, error = t)
        throw t
    }
}

inline fun <T> logAuthOperation(
    username: String?,
    extra: Map<String, Any?> = emptyMap(),
    operation: () -> T
): T {
    return try {
        val result = operation()
        AppLogger.logAuthAttempt(username, success = true, extra = extra)
        result
    } catch (t: Throwable) {
        AppLogger.logAuthAttempt(username, success = false, failureReason = t.message, extra = extra)
        throw t
    }
}

fun Throwable.stackTraceAsString(): String {
    val sw = StringWriter()
    printStackTrace(PrintWriter(sw))
    return sw.toString()
}

object GlobalExceptionLogger {
    fun install() {
        Thread.setDefaultUncaughtExceptionHandler { _, throwable ->
            AppLogger.logUnhandledException(throwable)
        }
    }
}

class LoggingSQLiteQueryCallback(
